DELETE FROM tb_ac_group
ar_code NOT IN #{c}
1 = 1

WITH sub AS (
  SELECT ac_group_id FROM tb_ac_group WHERE ac_group_id = #{acGroupId}
  UNION ALL
  SELECT g.ac_group_id FROM tb_ac_group g JOIN sub s ON g.parent_ac_group_id = s.ac_group_id
)
DELETE FROM tb_ac_group WHERE ac_group_id IN (SELECT ac_group_id FROM sub)
